import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Course } from '../../core/models';

/**
 * LearnLoop catalog — public landing showing all published courses.
 * Loads live data via ApiService.listCourses() in ngOnInit().
 */
@Component({
  selector: 'app-catalog',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './catalog.component.html',
  styleUrl: './catalog.component.css',
})
export class CatalogComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly courses = signal<Course[]>([
    {
      id: 'c1',
      title: 'Intro to Web Development',
      description:
        'Build your first web pages from scratch. Learn HTML structure, CSS styling, and the fundamentals of how the browser renders your work.',
      moduleCount: 2,
      lessonCount: 3,
      quizCount: 1,
    },
    {
      id: 'c2',
      title: 'JavaScript Foundations',
      description:
        'Master variables, functions, and control flow. A hands-on path from your first console.log to writing real interactive logic.',
      moduleCount: 3,
      lessonCount: 8,
      quizCount: 2,
    },
    {
      id: 'c3',
      title: 'Design Thinking Essentials',
      description:
        'A practical introduction to empathising with users, framing problems, and prototyping solutions that people actually want.',
      moduleCount: 2,
      lessonCount: 5,
      quizCount: 1,
    },
    {
      id: 'c4',
      title: 'Data Literacy for Everyone',
      description:
        'Read charts with confidence, spot misleading statistics, and turn raw numbers into a story your team can act on.',
      moduleCount: 4,
      lessonCount: 10,
      quizCount: 3,
    },
  ]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.listCourses().subscribe({
      next: (courses) => {
        this.courses.set(courses);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load courses. Please try again.');
        this.loading.set(false);
      },
    });
  }
}
